// Validate test results
const results = $input.all();

const validation = {
  total_vendors_processed: results.length,
  expected_vendors: 10,
  successful_syncs: results.filter(r => r.json.sync_status === 'success').length,
  failed_syncs: results.filter(r => r.json.sync_status === 'failed').length,
  expected_failures: 2,
  tier1_processed: results.filter(r => r.json.tier_used === 1).length,
  tier2_processed: results.filter(r => r.json.tier_used === 2).length,
  tier3_processed: results.filter(r => r.json.tier_used === 3).length,
  total_products_added: results.reduce((sum, r) => sum + (r.json.products_added || 0), 0),
  total_products_updated: results.reduce((sum, r) => sum + (r.json.products_updated || 0), 0),
  notifications_sent: results.filter(r => r.json.notification_sent).length
};

// Check if test passed
const testPassed = 
  validation.total_vendors_processed === validation.expected_vendors &&
  validation.failed_syncs === validation.expected_failures &&
  validation.successful_syncs === (validation.expected_vendors - validation.expected_failures);

return [{
  json: {
    ...validation,
    test_passed: testPassed,
    test_timestamp: new Date().toISOString(),
    test_summary: testPassed ? 
      '✅ All tests passed! Weekly sync workflow is functioning correctly.' :
      '❌ Test failed! Review the validation results for details.'
  }
}];

// Format success message
const results = $input.first().json;

const message = `
✅ **Weekly Sync Test PASSED**

**Test Summary:**
- Total Vendors: ${results.total_vendors_processed}/${results.expected_vendors}
- Successful Syncs: ${results.successful_syncs}
- Failed Syncs: ${results.failed_syncs}/${results.expected_failures} (expected)
- Tier 1 Processed: ${results.tier1_processed}
- Tier 2 Processed: ${results.tier2_processed}
- Tier 3 Processed: ${results.tier3_processed}
- Products Added: ${results.total_products_added}
- Products Updated: ${results.total_products_updated}
- Notifications Sent: ${results.notifications_sent}

**Status:** All systems operational ✅
**Time:** ${new Date().toLocaleString()}
`;

console.log(message);
return [{ json: { message, status: 'success' } }];

// Format failure message
const results = $input.first().json;

const message = `
❌ **Weekly Sync Test FAILED**

**Test Summary:**
- Total Vendors: ${results.total_vendors_processed}/${results.expected_vendors}
- Successful Syncs: ${results.successful_syncs}
- Failed Syncs: ${results.failed_syncs} (expected ${results.expected_failures})
- Tier 1 Processed: ${results.tier1_processed}
- Tier 2 Processed: ${results.tier2_processed}
- Tier 3 Processed: ${results.tier3_processed}

**Issues Detected:**
${results.total_vendors_processed !== results.expected_vendors ? '- Vendor count mismatch\n' : ''}
${results.failed_syncs !== results.expected_failures ? '- Unexpected failure count\n' : ''}

**Action Required:** Review workflow logs and fix issues
**Time:** ${new Date().toLocaleString()}
`;

console.error(message);
return [{ json: { message, status: 'failed' } }];
